代码 
public class AdapterPattern { 
    public static void main(String[] args) { 
        USB usb = new Adapter(); 
        usb.Request(); 
    } 
} 

class USB { 
    public void Request() { 
        System.out.println("USB 数据线"); 
    } 
} 

class Adapter extends USB { 
    private TypeC typeC = new TypeC(); 

    @Override 
    public void Request() { 
        typeC.SpecificRequest(); 
    } 
} 

